"use client";

import type { FormEvent } from "react";
import { useState } from "react";
import { SectionHeader } from "@/components/SectionHeader/SectionHeader";
import { profile } from "@/data/portfolio";
import styles from "./ContactSection.module.css";

export function ContactSection() {
  const [status, setStatus] = useState("");
  const shareSubject = encodeURIComponent(`Portfolio de ${profile.fullName}`);
  const shareBody = encodeURIComponent(`${profile.fullName} - ${profile.role}`);

  function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setStatus("Merci, ton message est prêt. Pour ce projet, le formulaire sert de démonstration côté interface.");
  }

  return (
    <section id="contact" className={styles.section}>
      <div>
        <SectionHeader
          label="Contact"
          title="Prêt à apprendre, contribuer et progresser dans une équipe ambitieuse."
          description="Je suis disponible pour discuter d'une opportunité, d'un stage, d'un projet ou d'une collaboration autour du développement web, du mobile, des réseaux ou de la cybersécurité."
        />

        <div className={styles.contactCards}>
          <a href={`mailto:${profile.email}`}>{profile.email}</a>
          <a href={`tel:${profile.phoneLink}`}>{profile.phone}</a>
          <span>{profile.location}</span>
          <span>{profile.socialName}</span>
        </div>
      </div>

      <form className={styles.form} onSubmit={handleSubmit}>
        <label>
          Nom
          <input name="name" type="text" placeholder="Votre nom" required />
        </label>
        <label>
          Email
          <input name="email" type="email" placeholder="votre.email@exemple.com" required />
        </label>
        <label>
          Message
          <textarea name="message" rows={5} placeholder="Écrivez votre message ici" required />
        </label>
        <button type="submit">Envoyer le message</button>
        {status ? <p className={styles.status}>{status}</p> : null}
        <div className={styles.shareBox} aria-label="Partager le portfolio">
          <p>Partager ce portfolio</p>
          <div>
            <button type="button" onClick={() => navigator.clipboard.writeText(window.location.href)}>
              Copier le lien
            </button>
            <a href={`mailto:?subject=${shareSubject}&body=${shareBody}`}>
              Partager par mail
            </a>
          </div>
        </div>
      </form>
    </section>
  );
}
